interface Component { void showPrice(); }
class Leaf implements Component {
    String name; int price;
    public Leaf(String n, int p) { name=n; price=p; }
    public void showPrice() { System.out.println(name + " : " + price); }
}

class Composite implements Component {
    String name;
    List<Component> comps = new ArrayList<>();
    public Composite(String n) { name=n; }
    public void addComponent(Component c) { comps.add(c); }
    public void showPrice() {
        System.out.println("Node: " + name);
        for(Component c : comps) c.showPrice();
    }
}

public class Main {
    public static void main(String[] args) {
        Component hd = new Leaf("HDD", 4000);
        Component mouse = new Leaf("Mouse", 500);
        Composite peri = new Composite("Peripheral");
        peri.addComponent(mouse);
        Composite comp = new Composite("Computer");
        comp.addComponent(hd);
        comp.addComponent(peri);
        comp.showPrice();
    }
}

