import java.util.*;

class TreeType { // Intrinsic, shared state
    private String name, color;
    public TreeType(String n, String c) { name=n; color=c; }
    public void draw(int x, int y) { System.out.println("Drawing " + name + " at " + x + "," + y); }
}

class TreeFactory {
    static Map<String, TreeType> types = new HashMap<>();
    public static TreeType getTreeType(String name, String color) {
        TreeType result = types.get(name);
        if(result == null) {
            result = new TreeType(name, color);
            types.put(name, result);
        }
        return result;
    }
}

public class Main {
    public static void main(String[] args) {
        TreeType t1 = TreeFactory.getTreeType("Oak", "Green");
        TreeType t2 = TreeFactory.getTreeType("Oak", "Green");
        t1.draw(10, 20);
        t2.draw(50, 60);
        System.out.println("Same shared object? " + (t1 == t2));
    }
}

