    }
}

abstract class Logger {
    public static int INFO = 1, DEBUG = 2;
    protected int level;
    protected Logger next;
    public void setNext(Logger l) { next = l; }
    public void logMessage(int lvl, String msg) {
        if(this.level <= lvl) write(msg);
        if(next != null) next.logMessage(lvl, msg);
    }
    abstract void write(String msg);
}

class ConsoleLogger extends Logger {
    public ConsoleLogger(int lvl) { this.level = lvl; }
    void write(String msg) { System.out.println("Console: " + msg); }
}

class FileLogger extends Logger {
    public FileLogger(int lvl) { this.level = lvl; }
    void write(String msg) { System.out.println("File: " + msg); }
}

public class Main {
    public static void main(String[] args) {
        Logger chain = new ConsoleLogger(Logger.INFO);
        chain.setNext(new FileLogger(Logger.DEBUG));

        chain.logMessage(Logger.INFO, "Information");
        System.out.println("---");
        chain.logMessage(Logger.DEBUG, "Debug info");
    }
}

