interface Expression { boolean interpret(String context); }
class TerminalExpression implements Expression {
    String data;
    public TerminalExpression(String data) { this.data = data; }
    public boolean interpret(String context) { return context.contains(data); }
}

class OrExpression implements Expression {
    Expression e1, e2;
    public OrExpression(Expression e1, Expression e2) { this.e1 = e1; this.e2 = e2; }
    public boolean interpret(String context) { return e1.interpret(context) || e2.interpret(context); }
}

public class Main {
    public static void main(String[] args) {
