        System.out.println("Is C++ present? " + isJavaOrSpring.interpret("I love C++"));
    }
}

interface Iterator { boolean hasNext(); Object next(); }
interface Container { Iterator getIterator(); }

class NameRepository implements Container {
    public String names[] = {"John", "Jane", "Alice"};
    public Iterator getIterator() {
        return new Iterator() {
            int index;
            public boolean hasNext() { return index < names.length; }
            public Object next() { return hasNext() ? names[index++] : null; }
        };
    }
}

public class Main {
    public static void main(String[] args) {
        NameRepository repo = new NameRepository();
        for(Iterator it = repo.getIterator(); it.hasNext();) {
            System.out.println("Name: " + it.next());
        }
    }
}

