import java.util.*;

class Memento {
    private String state;
    public Memento(String s) { state = s; }
    public String getState() { return state; }
}

class Originator {
    private String state;
    public void setState(String s) { state = s; }
    public String getState() { return state; }
    public Memento saveStateToMemento() { return new Memento(state); }
    public void getStateFromMemento(Memento m) { state = m.getState(); }
}

public class Main {
    public static void main(String[] args) {
        Originator o = new Originator();
        List<Memento> history = new ArrayList<>();

        o.setState("State 1");
        o.setState("State 2");
        history.add(o.saveStateToMemento()); // Save State 2

        o.setState("State 3");
        System.out.println("Current: " + o.getState());

        o.getStateFromMemento(history.get(0)); // Restore
        System.out.println("Restored: " + o.getState());
    }
}

import java.util.*;

class Subject {
    private List<Observer> observers = new ArrayList<>();
    private int state;
    public int getState() { return state; }
    public void setState(int s) { state = s; notifyAllObservers(); }
    public void attach(Observer o) { observers.add(o); }
    public void notifyAllObservers() { for(Observer o : observers) o.update(); }
}

abstract class Observer {
    protected Subject subject;
    public abstract void update();
}

class HexObserver extends Observer {
    public HexObserver(Subject s) { this.subject = s; this.subject.attach(this); }
    public void update() { System.out.println("Hex String: " + Integer.toHexString(subject.getState())); }
}

public class Main {
    public static void main(String[] args) {
        Subject sub = new Subject();
        new HexObserver(sub);
        System.out.println("State change: 15");
        sub.setState(15);
    }
}

